proof:
by
    constructor;
    · intro hx
      have hx_int : x ∈ Set.range (algebraMap (𝒪[K]) K) := by
        exact ⟨ ⟨ x, show ( valuation K ) x ≤ 1 from hx.le ⟩, rfl ⟩;
      obtain ⟨ r, rfl ⟩ := hx_int;
      have hr_unit : IsUnit r := by
        convert Valuation.Integers.isUnit_iff_valuation_eq_one (Valuation.integer.integers (valuation K)) |>.2 hx using 1
      obtain ⟨ u, hu ⟩ := hr_unit
      use u
      aesop;
    · rintro ⟨ r, rfl ⟩;
      exact Valuation.Integers.isUnit_iff_valuation_eq_one ( Valuation.integer.integers ( valuation K ) ) |>.1 ( Units.isUnit r )

